import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";

const TeacherDashboard = () => {
  const [darkMode] = useState(false);
  const [info, setInfo] = useState({});
  const [error, setError] = useState('');
  const token = localStorage.getItem('accessToken');
  const username = localStorage.getItem('username');

  useEffect(() => {
    fetch('http://localhost:8000/api/teacher-info/', {
      headers: { Authorization: `Bearer ${token}` },
    })
      .then(res => {
        if (!res.ok) throw new Error('Failed to fetch teacher info');
        return res.json();
      })
      .then(data => setInfo(data))
      .catch(() => setError('Unable to load teacher details.'));
  }, []);

  return (
    <div className={`container-fluid min-vh-100 py-5 ${darkMode ? 'bg-dark text-light' : 'bg-light text-dark'}`}>
      <div className="container">
        <div className="d-flex justify-content-between align-items-center mb-4">
          <h2>👨‍🏫 Teacher Dashboard</h2>
          <Link to="/profile" className="btn btn-secondary fw-bold">
            Hi, {username} 👋
          </Link>
        </div>

        <h5 className="text-center mb-4">Welcome, <span className="text-primary">{info.username}</span></h5>

        <div className="text-center mb-5">
          <p><strong>Email:</strong> {info.email}</p>
          <p><strong>Teacher ID:</strong> {info.teacher_id}</p>
        </div>

        <div className="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
          <div className="col">
            <Link to="/students" className="text-decoration-none">
              <div className="card bg-secondary text-white h-100 shadow">
                <div className="card-body text-center">
                  <h5 className="card-title">📚 Students</h5>
                  <p className="card-text">Manage all registered students.</p>
                </div>
              </div>
            </Link>
          </div>

          <div className="col">
            <Link to="/subjects" className="text-decoration-none">
              <div className="card bg-primary text-white h-100 shadow">
                <div className="card-body text-center">
                  <h5 className="card-title">📘 Subjects</h5>
                  <p className="card-text">View and manage school subjects.</p>
                </div>
              </div>
            </Link>
          </div>

          <div className="col">
            <Link to="/grades" className="text-decoration-none">
              <div className={`card h-100 shadow ${darkMode ? 'bg-light text-dark' : 'bg-dark text-light border border-light'}`}>
                <div className="card-body text-center">
                  <h5 className="card-title">🏅 Grades</h5>
                  <p className="card-text">Enter or review student performance.</p>
                </div>
              </div>
            </Link>
          </div>
        </div>

        {error && <div className="alert alert-danger mt-4 text-center">{error}</div>}
      </div>
    </div>
  );
};

export default TeacherDashboard;
